+fn emitBuiltinCall(self: *NativeCodegen, builtin: []const u8, args: []ast.Node) CodegenError!void {
+    const b = try self.getBuilder();
+    const builtin_name = try std.fmt.allocPrint(self.arena.allocator(), "@{s}", .{builtin});
